import os
from flask import Flask, request, redirect, url_for, session
from flask_oauthlib.client import OAuth

app = Flask(__name__)
app.config["SECRET_KEY"] = os.urandom(32)

oauth = OAuth(app)

# Register the OAuth provider with the appropriate redirect URI
oauth.register(
    name="my-oauth-provider",
    client_id=os.environ.get("OAUTH_CLIENT_ID"),
    client_secret=os.environ.get("OAUTH_CLIENT_SECRET"),
    access_token_url="https://example.com/oauth/token",
    authorize_url="https://example.com/oauth/authorize",
    redirect_uri=request.base_url + "/callback"
)

@app.route("/")
def index():
    # Redirect the user to the authorization URL
    return oauth.authorize(name="my-oauth-provider")

@app.route("/callback")
def callback():
    # Exchange the authorization code for an access token
    oauth.token_from_code(name="my-oauth-provider", code=request.args["code"])

    # Verify that the redirect URI is valid
    if not request.url.startswith(request.base_url + "/callback"):
        return "Invalid redirect URI", 403

    # Redirect the user to the home page
    return redirect(url_for("index"))